/**
 * Huddly ΓÇö Socket.io Real-Time Server (Hardened)
 *
 * Run: node server/socketServer.js
 *
 * Handles: player sync, movement, chat, meeting zones,
 * heartbeat/zombie cleanup, and health checks.
 */

const { Server } = require("socket.io");
const http = require("http");

const PORT = process.env.SOCKET_PORT || process.env.PORT || 3001;
const CLIENT_URL = process.env.CLIENT_URL || "http://localhost:3000";

// ΓöÇΓöÇ HTTP Server with health check & CORS preflight ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const server = http.createServer((req, res) => {
    // CORS preflight
    if (req.method === "OPTIONS") {
        res.writeHead(204, {
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "GET, OPTIONS",
            "Access-Control-Allow-Headers": "Content-Type",
            "Access-Control-Max-Age": "86400",
        });
        res.end();
        return;
    }

    // Health check
    if (req.method === "GET" && req.url === "/health") {
        res.writeHead(200, {
            "Content-Type": "application/json",
            "Access-Control-Allow-Origin": "*",
        });
        res.end(JSON.stringify({
            status: "alive",
            uptime: process.uptime(),
            players: players.size,
            timestamp: new Date().toISOString(),
        }));
        return;
    }

    // Stats endpoint
    if (req.method === "GET" && req.url === "/stats") {
        const roomCounts = {};
        for (const [, player] of players) {
            roomCounts[player.room] = (roomCounts[player.room] || 0) + 1;
        }
        res.writeHead(200, {
            "Content-Type": "application/json",
            "Access-Control-Allow-Origin": "*",
        });
        res.end(JSON.stringify({
            totalPlayers: players.size,
            rooms: roomCounts,
        }));
        return;
    }

    res.writeHead(404);
    res.end();
});

// ΓöÇΓöÇ Socket.IO ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const io = new Server(server, {
    cors: {
        origin: CLIENT_URL,
        methods: ["GET", "POST"],
    },
    pingInterval: 10000,  // Send ping every 10s
    pingTimeout: 5000,    // Disconnect if no pong within 5s
    maxHttpBufferSize: 1e8, // 100 MB for Whiteboard base64 Sync
});

// ΓöÇΓöÇ In-memory state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const players = new Map();

// ΓöÇΓöÇ Connection handler ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
io.on("connection", (socket) => {
    const { userName, roomId } = socket.handshake?.query || {};
    const name = userName || `Guest_${socket.id.slice(0, 4)}`;
    const room = roomId || "office";

    console.log(`[+] ${name} joined room "${room}" (${socket.id})`);

    // Join Socket.io room
    socket.join(room);

    // Register player
    const player = {
        id: socket.id,
        name,
        x: 0,
        y: 0.6,
        z: 24,
        zone: "Lobby",
        meetingZone: null,
        color: `hsl(${Math.random() * 360}, 60%, 45%)`,
        room,
        lastPing: Date.now(),
    };
    players.set(socket.id, player);

    // Notify others in room
    socket.to(room).emit("player:joined", player);

    // Send existing players to new joiner
    const roomPlayers = Array.from(players.values()).filter(p => p.room === room);
    socket.emit("players:sync", roomPlayers);

    // ΓöÇΓöÇ Movement ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    socket.on("player:move", (data) => {
        const p = players.get(socket.id);
        if (!p) return;

        p.x = data.x;
        p.y = data.y;
        p.z = data.z;
        p.zone = data.zone || p.zone;
        p.lastPing = Date.now();

        socket.to(room).emit("player:moved", {
            id: socket.id,
            x: data.x,
            y: data.y,
            z: data.z,
            zone: data.zone,
        });
    });

    // ΓöÇΓöÇ Chat ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    socket.on("chat:message", (data) => {
        if (!data || !data.message) return;
        io.to(room).emit("chat:message", {
            id: Date.now().toString(),
            user: name,
            text: data.message.slice(0, 500), // Limit message length
            time: "now",
            type: data.channel || "global",
        });
    });

    // ΓöÇΓöÇ Whiteboard sync ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    socket.on("whiteboard:update", (dataUrl) => {
        // Relay the whiteboard canvas to all other players in the room
        socket.to(room).emit("whiteboard:update", dataUrl);
    });

    // ΓöÇΓöÇ Meeting zone tracking ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    socket.on("meeting:join", (meetingZone) => {
        if (!meetingZone) return;
        const p = players.get(socket.id);
        if (p) p.meetingZone = meetingZone;

        socket.join(`${room}:${meetingZone}`);
        io.to(`${room}:${meetingZone}`).emit("meeting:participant-joined", {
            id: socket.id,
            name,
            zone: meetingZone,
        });

        // Send list of all participants in this meeting zone
        const meetingParticipants = Array.from(players.values())
            .filter(pl => pl.room === room && pl.meetingZone === meetingZone)
            .map(pl => ({ id: pl.id, name: pl.name }));
        socket.emit("meeting:participants", meetingParticipants);
    });

    socket.on("meeting:leave", (meetingZone) => {
        if (!meetingZone) return;
        const p = players.get(socket.id);
        if (p) p.meetingZone = null;

        socket.leave(`${room}:${meetingZone}`);
        io.to(`${room}:${meetingZone}`).emit("meeting:participant-left", {
            id: socket.id,
        });
    });

    // ΓöÇΓöÇ WebRTC signaling relay ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    socket.on("webrtc:offer", (data) => {
        if (data?.target && data?.offer) {
            socket.to(data.target).emit("webrtc:offer", { from: socket.id, offer: data.offer });
        }
    });

    socket.on("webrtc:answer", (data) => {
        if (data?.target && data?.answer) {
            socket.to(data.target).emit("webrtc:answer", { from: socket.id, answer: data.answer });
        }
    });

    socket.on("webrtc:ice-candidate", (data) => {
        if (data?.target && data?.candidate) {
            socket.to(data.target).emit("webrtc:ice-candidate", { from: socket.id, candidate: data.candidate });
        }
    });

    // ΓöÇΓöÇ Disconnect ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    socket.on("disconnect", (reason) => {
        console.log(`[-] ${name} left (${socket.id}) reason: ${reason}`);
        players.delete(socket.id);
        io.to(room).emit("player:left", socket.id);
    });

    // ΓöÇΓöÇ Error handling ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    socket.on("error", (err) => {
        console.error(`[!] Socket error for ${name} (${socket.id}):`, err.message);
    });
});

// ΓöÇΓöÇ Zombie cleanup interval (every 60s) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
setInterval(() => {
    const now = Date.now();
    const timeout = 120000; // 2 minutes
    for (const [id, player] of players) {
        if (now - player.lastPing > timeout) {
            console.log(`[≡ƒº╣] Cleaning zombie: ${player.name} (${id})`);
            players.delete(id);
            io.to(player.room).emit("player:left", id);
        }
    }
}, 60000);

// ΓöÇΓöÇ Start server ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
server.listen(PORT, () => {
    console.log(`\n≡ƒÅó Huddly Socket Server running on port ${PORT}`);
    console.log(`   Client URL: ${CLIENT_URL}`);
    console.log(`   Health: http://localhost:${PORT}/health`);
    console.log(`   Stats:  http://localhost:${PORT}/stats`);
    console.log(`   WebSocket ready for connections\n`);
});

// ΓöÇΓöÇ Graceful shutdown ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
process.on("SIGTERM", () => {
    console.log("[!] SIGTERM received, shutting down gracefully...");
    io.close();
    server.close(() => process.exit(0));
});

import { NextRequest, NextResponse } from "next/server";
import { AccessToken } from "livekit-server-sdk";
import { currentUser } from "@clerk/nextjs/server";

export async function GET(req: NextRequest) {
    try {
        const room = req.nextUrl.searchParams.get("room");
        const usernameParam = req.nextUrl.searchParams.get("username");

        if (!room) {
            return NextResponse.json(
                { error: 'Missing "room" query parameter' },
                { status: 400 }
            );
        }

        const apiKey = process.env.LIVEKIT_API_KEY;
        const apiSecret = process.env.LIVEKIT_API_SECRET;
        const wsUrl = process.env.NEXT_PUBLIC_LIVEKIT_URL;

        if (!apiKey || !apiSecret || !wsUrl) {
            return NextResponse.json(
                { error: "Server misconfigured. LiveKit keys are missing." },
                { status: 500 }
            );
        }

        // Try to get authenticated user from Clerk
        const user = await currentUser();

        // Fallback to guest or requested name if not logged in (development)
        const participantIdentity = user?.id || `guest-${Math.random().toString(36).substring(2, 9)}`;
        const participantName = user?.firstName || user?.username || usernameParam || "Guest User";

        const at = new AccessToken(apiKey, apiSecret, {
            identity: participantIdentity,
            name: participantName,
        });

        at.addGrant({ room, roomJoin: true, canPublish: true, canSubscribe: true });

        const token = await at.toJwt();

        return NextResponse.json({ token, identity: participantIdentity, name: participantName });
    } catch (error: any) {
        console.error("LiveKit token generation error:", error);
        return NextResponse.json(
            { error: "Failed to generate token" },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { currentUser } from "@clerk/nextjs/server";

// GET /api/rooms/[id] ΓÇö Fetch a single room
export async function GET(
    request: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    const { id } = await params;

    try {
        const supabase = await createClient();
        const { data, error } = await supabase
            .from("rooms")
            .select("*")
            .eq("id", id)
            .single();

        if (error) throw error;

        return NextResponse.json(data);
    } catch {
        return NextResponse.json(
            { error: "Room not found" },
            { status: 404 }
        );
    }
}

// PATCH /api/rooms/[id] ΓÇö Update a room (owner only)
export async function PATCH(
    request: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    const { id } = await params;

    try {
        const user = await currentUser();
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const body = await request.json();
        const allowedFields = ["name", "description", "visibility", "max_capacity", "template", "custom_objects", "map_data"];
        const updates: Record<string, unknown> = {};

        for (const field of allowedFields) {
            if (body[field] !== undefined) {
                updates[field] = body[field];
            }
        }

        if (Object.keys(updates).length === 0) {
            return NextResponse.json({ error: "No valid fields to update" }, { status: 400 });
        }

        const supabase = await createClient();

        // Verify ownership
        const { data: room } = await supabase
            .from("rooms")
            .select("owner_id")
            .eq("id", id)
            .single();

        if (!room) {
            return NextResponse.json({ error: "Room not found" }, { status: 404 });
        }

        if (room.owner_id !== user.id && room.owner_id !== "system") {
            return NextResponse.json({ error: "Not authorized to update this room" }, { status: 403 });
        }

        const { data, error } = await supabase
            .from("rooms")
            .update(updates)
            .eq("id", id)
            .select()
            .single();

        if (error) throw error;

        return NextResponse.json(data);
    } catch (err: any) {
        return NextResponse.json(
            { error: err.message || "Failed to update room" },
            { status: 500 }
        );
    }
}

// DELETE /api/rooms/[id] ΓÇö Delete a room (owner only)
export async function DELETE(
    request: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    const { id } = await params;

    try {
        const user = await currentUser();
        if (!user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const supabase = await createClient();

        // Verify ownership
        const { data: room } = await supabase
            .from("rooms")
            .select("owner_id")
            .eq("id", id)
            .single();

        if (!room) {
            return NextResponse.json({ error: "Room not found" }, { status: 404 });
        }

        if (room.owner_id !== user.id) {
            return NextResponse.json({ error: "Not authorized to delete this room" }, { status: 403 });
        }

        if (room.owner_id === "system") {
            return NextResponse.json({ error: "Cannot delete system rooms" }, { status: 403 });
        }

        const { error } = await supabase
            .from("rooms")
            .delete()
            .eq("id", id);

        if (error) throw error;

        return NextResponse.json({ success: true });
    } catch (err: any) {
        return NextResponse.json(
            { error: err.message || "Failed to delete room" },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
