const VALID_TEMPLATES = ["classroom", "office", "cafe", "conference", "party", "library", "gaming", "rooftop", "theater", "blank", "custom"];

// In-memory fallback rooms
const fallbackRooms = [
    { id: "office", name: "Team HQ ≡ƒÅó", description: "Our virtual office", template: "office", max_capacity: 50, visibility: "public", custom_objects: [], owner_id: "system", online_count: 0, created_at: "2026-02-01T00:00:00Z" },
