                            <span className="text-[10px] text-gray-500">{incident.date}</span>
                        </div>
                        <p className="text-xs text-gray-400 leading-relaxed">{incident.description}</p>
                    </motion.div>
                ))}
            </div>
        </ContentPageLayout>
    );
}

