                                    <motion.div
                                        className="absolute inset-0 rounded-3xl border border-emerald-500"
                                        animate={{ scale: [1, 2], opacity: [0.5, 0] }}
                                        transition={{ duration: 2, repeat: Infinity, ease: "easeOut" }}
