    isOpen: boolean;
    onClose: () => void;
}

const QUICK_REACTIONS = ["≡ƒæì", "Γ¥ñ∩╕Å", "≡ƒÿé", "≡ƒÄë", "≡ƒñö", "≡ƒæÇ"];

export default function ChatSidebar({ isOpen, onClose }: ChatSidebarProps) {
    const chatMessages = useRealtimeStore(s => s.chatMessages);
    const sendChat = useRealtimeStore(s => s.sendChat);
    const connected = useRealtimeStore(s => s.connected);
    const typingUsers = useRealtimeStore(s => s.typingUsers);
    const setTyping = useRealtimeStore(s => s.setTyping);
    const addReaction = useRealtimeStore(s => s.addReaction);

    const [input, setInput] = useState("");
    const [activeTab, setActiveTab] = useState<"global" | "proximity">("global");
    const [showScrollButton, setShowScrollButton] = useState(false);
    const [reactingMessageId, setReactingMessageId] = useState<string | null>(null);
    const [unreadCount, setUnreadCount] = useState(0);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const isAtBottomRef = useRef(true);

    // Auto-scroll when new messages + user is at bottom
    useEffect(() => {
        if (isAtBottomRef.current) {
            messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
            setUnreadCount(0);
        } else {
            setUnreadCount(prev => prev + 1);
        }
    }, [chatMessages]);

    // Reset unread when opened
    useEffect(() => {
        if (isOpen) setUnreadCount(0);
    }, [isOpen]);

    const handleScroll = useCallback(() => {
        const container = scrollContainerRef.current;
        if (!container) return;
        const isNearBottom = container.scrollHeight - container.scrollTop - container.clientHeight < 60;
        isAtBottomRef.current = isNearBottom;
        setShowScrollButton(!isNearBottom);
        if (isNearBottom) setUnreadCount(0);
    }, []);

    const scrollToBottom = useCallback(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
        setUnreadCount(0);
    }, []);

    const sendMessage = () => {
        if (!input.trim()) return;
        sendChat(input.trim(), activeTab);
        setInput("");
        setTyping(false);
        if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    };

    const handleInputChange = (value: string) => {
        setInput(value);
        // Typing indicator
        setTyping(true);
        if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
        typingTimeoutRef.current = setTimeout(() => setTyping(false), 2000);
    };

    const filteredMessages = chatMessages.filter(
        (m) => m.type === activeTab || m.type === "system"
    );

    return (
        <AnimatePresence>
            {isOpen && (
                <motion.div
                    initial={{ x: 320, opacity: 0 }}
                    animate={{ x: 0, opacity: 1 }}
                    exit={{ x: 320, opacity: 0 }}
                    transition={{ type: "spring", damping: 22, stiffness: 250 }}
                    className="fixed right-0 top-0 bottom-0 w-80 bg-white/98 backdrop-blur-xl border-l border-gray-200/60 z-30 flex flex-col shadow-2xl shadow-black/5"
                >
                    {/* Header */}
                    <div className="flex items-center justify-between px-4 h-14 border-b border-gray-100">
                        <div className="flex items-center gap-2 text-gray-900 font-semibold">
                            <MessageCircle className="w-4 h-4 text-emerald-600" />
                            Chat
                            {!connected && (
                                <motion.span
                                    initial={{ scale: 0 }}
                                    animate={{ scale: 1 }}
                                    className="text-[10px] text-amber-500 bg-amber-50 px-1.5 py-0.5 rounded-full font-medium"
                                >
                                    Offline
                                </motion.span>
                            )}
                            {unreadCount > 0 && !isOpen && (
                                <motion.span
                                    initial={{ scale: 0 }}
                                    animate={{ scale: 1 }}
                                    className="text-[10px] text-white bg-red-500 px-1.5 py-0.5 rounded-full font-bold min-w-[18px] text-center"
                                >
                                    {unreadCount}
                                </motion.span>
                            )}
                        </div>
                        <motion.button
                            whileHover={{ scale: 1.1 }}
                            whileTap={{ scale: 0.9 }}
                            onClick={onClose}
                            className="p-1.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-all"
                        >
                            <X className="w-4 h-4" />
                        </motion.button>
                    </div>

                    {/* Tabs */}
                    <div className="flex border-b border-gray-100 relative">
                        {(["global", "proximity"] as const).map((tab) => (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className={`flex-1 px-4 py-2.5 text-xs font-medium flex items-center justify-center gap-1.5 transition-colors relative ${activeTab === tab
                                        ? "text-emerald-600"
                                        : "text-gray-400 hover:text-gray-600"
                                    }`}
                            >
                                {tab === "global" ? <Hash className="w-3 h-3" /> : <UsersIcon className="w-3 h-3" />}
                                {tab === "global" ? "Global" : "Nearby"}
                                {activeTab === tab && (
                                    <motion.div
                                        layoutId="chatTab"
                                        className="absolute bottom-0 left-0 right-0 h-0.5 bg-emerald-500"
                                        transition={{ type: "spring", damping: 20, stiffness: 300 }}
                                    />
                                )}
                            </button>
                        ))}
                    </div>

                    {/* Messages */}
                    <div
                        ref={scrollContainerRef}
                        className="flex-1 overflow-y-auto p-4 space-y-2 relative"
                        onScroll={handleScroll}
                    >
                        {filteredMessages.length === 0 && (
                            <motion.div
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="text-center text-xs text-gray-400 py-8"
                            >
                                No messages yet. Say hi! ≡ƒæï
                            </motion.div>
                        )}
                        <AnimatePresence initial={false}>
                            {filteredMessages.map((msg, i) => (
                                <motion.div
                                    key={msg.id}
                                    initial={{ opacity: 0, y: 8, scale: 0.95 }}
                                    animate={{ opacity: 1, y: 0, scale: 1 }}
                                    transition={{ duration: 0.2 }}
                                    className={`${msg.type === "system"
                                            ? "text-center text-[11px] text-gray-400 italic py-1"
                                            : ""
                                        }`}
                                >
                                    {msg.type !== "system" && (
                                        <div
                                            className={`group ${msg.user === "You" ? "ml-auto max-w-[85%]" : "max-w-[85%]"}`}
                                        >
                                            <div className="flex items-baseline gap-2 mb-0.5">
                                                <span className={`text-xs font-semibold ${msg.user === "You" ? "text-emerald-600" : "text-gray-700"
                                                    }`}>
                                                    {msg.user}
                                                </span>
                                                <span className="text-[10px] text-gray-400">{msg.time}</span>
                                            </div>
                                            <div className={`px-3 py-1.5 rounded-xl text-sm relative ${msg.user === "You"
                                                    ? "bg-emerald-50 text-emerald-800 rounded-tr-sm"
                                                    : "bg-gray-50 text-gray-700 rounded-tl-sm"
                                                }`}>
                                                {msg.text}
                                                {/* Reaction button */}
                                                <button
                                                    onClick={() => setReactingMessageId(
                                                        reactingMessageId === msg.id ? null : msg.id
                                                    )}
                                                    className="absolute -right-1 -top-1 opacity-0 group-hover:opacity-100 transition-opacity w-5 h-5 rounded-full bg-white border border-gray-200 flex items-center justify-center shadow-sm"
                                                >
                                                    <Smile className="w-3 h-3 text-gray-400" />
                                                </button>
                                            </div>
                                            {/* Reactions display */}
                                            {msg.reactions && Object.keys(msg.reactions).length > 0 && (
                                                <div className="flex flex-wrap gap-1 mt-1">
                                                    {Object.entries(msg.reactions).map(([emoji, users]) => (
                                                        <button
                                                            key={emoji}
                                                            onClick={() => addReaction(msg.id, emoji)}
                                                            className={`text-[11px] px-1.5 py-0.5 rounded-full border transition-all ${(users as string[]).includes("You")
                                                                    ? "bg-emerald-50 border-emerald-200 text-emerald-700"
                                                                    : "bg-gray-50 border-gray-200 text-gray-500 hover:bg-gray-100"
                                                                }`}
                                                        >
                                                            {emoji} {(users as string[]).length}
                                                        </button>
                                                    ))}
                                                </div>
                                            )}
                                            {/* Reaction picker */}
                                            <AnimatePresence>
                                                {reactingMessageId === msg.id && (
                                                    <motion.div
                                                        initial={{ opacity: 0, scale: 0.8, y: -5 }}
                                                        animate={{ opacity: 1, scale: 1, y: 0 }}
                                                        exit={{ opacity: 0, scale: 0.8, y: -5 }}
                                                        className="flex gap-1 mt-1 p-1 rounded-lg bg-white border border-gray-200 shadow-lg w-fit"
                                                    >
                                                        {QUICK_REACTIONS.map((emoji) => (
                                                            <button
                                                                key={emoji}
                                                                onClick={() => {
                                                                    addReaction(msg.id, emoji);
                                                                    setReactingMessageId(null);
                                                                }}
                                                                className="w-7 h-7 flex items-center justify-center rounded-md hover:bg-gray-100 transition-colors text-sm"
                                                            >
                                                                {emoji}
                                                            </button>
                                                        ))}
                                                    </motion.div>
                                                )}
                                            </AnimatePresence>
                                        </div>
                                    )}
                                    {msg.type === "system" && <span>{msg.text}</span>}
                                </motion.div>
                            ))}
                        </AnimatePresence>
                        <div ref={messagesEndRef} />
                    </div>

                    {/* Scroll to bottom button */}
                    <AnimatePresence>
                        {showScrollButton && (
                            <motion.button
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: 10 }}
                                onClick={scrollToBottom}
                                className="absolute bottom-20 left-1/2 -translate-x-1/2 z-10 px-3 py-1.5 rounded-full bg-gray-900/80 text-white text-xs font-medium flex items-center gap-1.5 shadow-lg backdrop-blur-sm"
                            >
                                <ChevronDown className="w-3 h-3" />
                                {unreadCount > 0 ? `${unreadCount} new` : "Scroll down"}
                            </motion.button>
                        )}
                    </AnimatePresence>

                    {/* Typing indicator */}
                    <AnimatePresence>
                        {typingUsers.length > 0 && (
                            <motion.div
                                initial={{ opacity: 0, height: 0 }}
                                animate={{ opacity: 1, height: "auto" }}
                                exit={{ opacity: 0, height: 0 }}
                                className="px-4 py-1"
                            >
                                <div className="text-xs text-gray-400 flex items-center gap-1.5">
                                    <div className="flex gap-0.5">
                                        {[0, 1, 2].map((i) => (
                                            <motion.span
                                                key={i}
                                                animate={{ opacity: [0.3, 1, 0.3] }}
                                                transition={{ duration: 1.2, repeat: Infinity, delay: i * 0.2 }}
                                                className="w-1 h-1 rounded-full bg-gray-400"
                                            />
                                        ))}
                                    </div>
                                    <span>
                                        {typingUsers.length === 1
                                            ? `${typingUsers[0]} is typing`
                                            : `${typingUsers.length} people typing`}
                                    </span>
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {/* Input */}
                    <div className="p-3 border-t border-gray-100">
                        <div className="flex gap-2">
                            <Input
                                placeholder={`Message ${activeTab === "proximity" ? "nearby" : "everyone"}...`}
                                value={input}
                                onChange={(e) => handleInputChange(e.target.value)}
                                onKeyDown={(e) => e.key === "Enter" && sendMessage()}
                                className="flex-1 h-9 text-xs bg-gray-50 border-gray-200 focus:ring-emerald-500 focus:border-emerald-500"
                                disabled={!connected}
                            />
                            <motion.button
                                whileHover={{ scale: 1.05 }}
                                whileTap={{ scale: 0.9 }}
                                onClick={sendMessage}
                                disabled={!connected}
                                className="p-2 bg-emerald-600 hover:bg-emerald-700 disabled:bg-gray-300 text-white rounded-lg transition-colors"
                            >
                                <Send className="w-3.5 h-3.5" />
                            </motion.button>
                        </div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}

"use client";

import React, { useEffect, useState, useRef, useCallback } from "react";
import { LiveKitRoom } from "@livekit/components-react";
import { motion, AnimatePresence } from "framer-motion";
import { Wifi, WifiOff, RefreshCw, AlertTriangle } from "lucide-react";
import "@livekit/components-styles";

interface LiveKitWrapperProps {
    roomId: string;
    userName?: string;
    children: React.ReactNode;
}

export default function LiveKitWrapper({ roomId, userName, children }: LiveKitWrapperProps) {
    const [token, setToken] = useState("");
    const [error, setError] = useState<string | null>(null);
    const [isReconnecting, setIsReconnecting] = useState(false);
    const [connectionState, setConnectionState] = useState<"connecting" | "connected" | "disconnected">("connecting");
    const serverUrl = process.env.NEXT_PUBLIC_LIVEKIT_URL || "";
    const retryCountRef = useRef(0);
    const maxRetries = 5;
    const mountedRef = useRef(true);

    const fetchToken = useCallback(async () => {
        try {
            if (mountedRef.current) setError(null);
            const res = await fetch(`/api/livekit?room=${roomId}&username=${encodeURIComponent(userName || "Guest")}`);

            if (!res.ok) {
                const errData = await res.json().catch(() => ({ error: `HTTP ${res.status}` }));
                throw new Error(errData.error || `HTTP ${res.status}`);
            }

            const data = await res.json();

            if (mountedRef.current && data.token) {
                setToken(data.token);
                setIsReconnecting(false);
                retryCountRef.current = 0;
                console.log("[LiveKit] Token fetched successfully");
            } else if (data.error) {
                throw new Error(data.error);
            }
        } catch (e: any) {
            console.error("[LiveKit] Token fetch failed:", e.message);

            if (mountedRef.current && retryCountRef.current < maxRetries) {
                const backoffMs = Math.min(1000 * Math.pow(2, retryCountRef.current), 10000);
                retryCountRef.current += 1;
                console.log(`[LiveKit] Retrying in ${backoffMs}ms (attempt ${retryCountRef.current}/${maxRetries})`);
                setTimeout(() => {
                    if (mountedRef.current) fetchToken();
                }, backoffMs);
            } else if (mountedRef.current) {
                setError("Failed to connect to media server after multiple attempts.");
                setIsReconnecting(false);
            }
        }
    }, [roomId, userName]);

    useEffect(() => {
        mountedRef.current = true;
        if (serverUrl) {
            fetchToken();
        }
        return () => {
            mountedRef.current = false;
        };
    }, [roomId, userName, serverUrl, fetchToken]);

    const handleDisconnected = useCallback(() => {
        console.log("[LiveKit] Disconnected ΓÇö will re-fetch token");
        setIsReconnecting(true);
        setConnectionState("disconnected");
        retryCountRef.current = 0;
        setTimeout(() => {
            if (mountedRef.current) fetchToken();
        }, 2000);
    }, [fetchToken]);

    if (!serverUrl) {
        return (
            <div className="w-full h-full relative">
                <AnimatePresence>
                    <motion.div
                        initial={{ opacity: 0, y: -20 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -20 }}
                        className="absolute top-14 left-1/2 -translate-x-1/2 z-[100] px-5 py-3 rounded-2xl bg-amber-50/95 backdrop-blur-xl border border-amber-200/60 text-amber-800 text-xs font-medium max-w-sm text-center shadow-2xl shadow-amber-500/10 flex items-center gap-3"
                    >
                        <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0" />
                        <span>Missing NEXT_PUBLIC_LIVEKIT_URL. Audio/Video features are disabled.</span>
                    </motion.div>
                </AnimatePresence>
                {children}
            </div>
        );
    }

    if (error) {
        return (
            <div className="w-full h-full relative">
                <motion.div
                    initial={{ opacity: 0, y: -20, scale: 0.95 }}
                    animate={{ opacity: 1, y: 0, scale: 1 }}
                    className="absolute top-14 left-1/2 -translate-x-1/2 z-[100] px-5 py-4 rounded-2xl bg-red-50/95 backdrop-blur-xl border border-red-200/60 shadow-2xl shadow-red-500/10 text-red-800 text-sm font-medium max-w-sm text-center flex flex-col items-center gap-3"
                >
                    <WifiOff className="w-5 h-5 text-red-400" />
                    <span>{error}</span>
                    <motion.button
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                        onClick={() => {
                            setError(null);
                            retryCountRef.current = 0;
                            fetchToken();
                        }}
                        className="px-4 py-1.5 bg-white rounded-full text-red-600 font-semibold hover:bg-red-50 transition-colors shadow-sm ring-1 ring-red-100 flex items-center gap-2"
                    >
                        <RefreshCw className="w-3.5 h-3.5" />
                        Retry Connection
                    </motion.button>
                </motion.div>
            </div>
        );
    }

    if (token === "") {
        return (
            <div className="w-full h-full flex flex-col items-center justify-center bg-white/50 backdrop-blur-sm text-slate-500 z-50">
                <motion.div
                    animate={{ rotate: 360 }}
                    transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                    className="w-8 h-8 rounded-full border-[3px] border-emerald-500 border-t-transparent mb-4 shadow-sm"
                />
                <motion.span
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="font-medium text-sm text-slate-700"
                >
                    Connecting to Secure Server...
                </motion.span>
            </div>
        );
    }

    return (
        <div className="w-full h-full relative">
            {/* Reconnection banner */}
            <AnimatePresence>
                {isReconnecting && (
                    <motion.div
                        initial={{ opacity: 0, y: -10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        className="absolute top-4 right-4 z-[100] px-4 py-2 rounded-full bg-amber-50/95 backdrop-blur-xl border border-amber-200/60 text-amber-800 text-xs font-semibold flex items-center justify-center gap-2 shadow-lg shadow-amber-500/10"
                    >
                        <motion.div
                            animate={{ rotate: 360 }}
                            transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                            className="w-3 h-3 rounded-full border-2 border-amber-500 border-t-transparent"
                        />
                        Reconnecting to media server...
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Connection success indicator */}
            <AnimatePresence>
                {connectionState === "connected" && (
                    <motion.div
                        initial={{ opacity: 0, y: -10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        transition={{ delay: 0.2 }}
                        className="absolute top-4 right-4 z-[100] px-3 py-1.5 rounded-full bg-emerald-50/95 backdrop-blur-xl border border-emerald-200/60 text-emerald-700 text-xs font-semibold flex items-center gap-2 shadow-lg"
                    >
                        <Wifi className="w-3 h-3" />
                        Connected
                    </motion.div>
                )}
            </AnimatePresence>

            <LiveKitRoom
                video={true}
                audio={true}
                token={token}
                serverUrl={serverUrl}
                data-lk-theme="default"
                className="w-full h-full"
                connectOptions={{
                    autoSubscribe: true,
                    maxRetries: 5,
                }}
                options={{
                    audioCaptureDefaults: {
                        autoGainControl: true,
                        noiseSuppression: true,
                        echoCancellation: true,
                    },
                    videoCaptureDefaults: {
                        resolution: {
                            width: 640,
                            height: 480,
                            frameRate: 24,
                        },
                    },
                    adaptiveStream: true,
                    dynacast: true,
                }}
                onConnected={() => {
                    console.log("[LiveKit] Connected successfully");
                    setIsReconnecting(false);
                    setConnectionState("connected");
                    // Auto-hide the connected indicator after 3s
                    setTimeout(() => setConnectionState("connecting"), 3000);
                }}
                onDisconnected={handleDisconnected}
                onMediaDeviceFailure={(failure) => {
                    console.warn("[LiveKit] Media device failure:", failure);
                    // Don't show error ΓÇö user may have denied permissions intentionally
                }}
                onError={(err) => {
                    console.error("[LiveKit] Room error:", err);
                }}
            >
                {children}
            </LiveKitRoom>
        </div>
    );
}

